// src/api/auth.js
// src/api/auth.js
import axios from "axios";

const API_URL = "https://prasa-app-yde3.onrender.com/api/app";
// If testing locally:
// const API_URL = "http://localhost:9000/api/app";

export const loginUser = async (empId, password) => {
  try {
    const res = await axios.post(API_URL, {
      action: "login",
      empId,
      password,
    });

    return res;  // <-- important: return whole axios response
  } catch (err) {
    console.error("LOGIN API ERROR →", err);

    return {
      data: {
        success: false,
        message: "SERVER_ERROR",
      },
    };
  }
};

export const getDashboard = (empId) => {
  return axios.post(API_URL, { action: "dashboard", empId });
};

export const addTravel = (payload) => {
  return axios.post(API_URL, { action: "addTravel", ...payload });
};

export const addTicket = (payload) => {
  return axios.post(API_URL, { action: "addTicket", ...payload });
};

export const getHistory = (empId) => {
  return axios.post(API_URL, { action: "getHistory", empId });
};

export const getGraphData = (empId) => {
  return axios.post(API_URL, { action: "getGraphData", empId });
};

export const uploadBill = (payload) => {
  return axios.post(API_URL, { action: "uploadBill", ...payload });
};

export const generateReport = (payload) => {
  return axios.post(API_URL, { action: "generateReport", ...payload });
};
